const http = require('http');
const https = require('https');
const body = $json.body || $json;
const method = (body.method || 'GET').toUpperCase();
const url = body.url || '';
const headers = body.headers || {};
const reqBody = body.body || null;

if (!url) return [{ json: { output: '❌ Falta el parámetro url' } }];

return new Promise((resolve) => {
  const lib = url.startsWith('https') ? https : http;
  const opts = { method, headers: { ...headers, 'User-Agent': 'NIN-Agent/1.0' } };
  const req = lib.request(url, opts, (res) => {
    let data = '';
    res.on('data', (chunk) => data += chunk);
    res.on('end', () => {
      resolve([{ json: { output: `HTTP ${res.statusCode}\n\n${data.substring(0, 8000)}` } }]);
    });
  });
  req.on('error', (e) => resolve([{ json: { output: '❌ Error: ' + e.message } }]));
  if (reqBody) req.write(typeof reqBody === 'string' ? reqBody : JSON.stringify(reqBody));
  req.end();
});
